INSERT INTO public.agent_sql_runs (id,message_id,executed_sql,bq_result,created_at) VALUES
('d2abb0d8-a195-4b4e-8c78-2ade1f118ba6','d8f2aede-1914-4cd0-afa1-c587be586718','WITH attendance AS ( SELECT branch, COUNT(DISTINCT contact) AS attendance FROM `tenms-userdb.Marketing_Leads.offline_leads_api` WHERE attendance_date BETWEEN CURRENT_DATE() - 29 AND CURRENT_DATE() GROUP BY branch ), admissions AS ( SELECT branch, COUNT(DISTINCT Mobile_Number) AS admissions FROM `tenms-userdb.english_centre.offline_admissions_gsheet_v3` WHERE admission_date BETWEEN CURRENT_DATE() - 29 AND CURRENT_DATE() GROUP BY branch ) SELECT COALESCE(a.branch, ad.branch) AS branch, IFNULL(attendance, 0) AS attendance, IFNULL(admissions, 0) AS admissions, ROUND(SAFE_DIVIDE(IFNULL(admissions, 0), NULLIF(IFNULL(attendance, 0), 0)) * 100, 0) AS ata_percent FROM attendance a FULL OUTER JOIN admissions ad ON a.branch = ad.branch ORDER BY CASE COALESCE(a.branch, ad.branch) WHEN ''Uttara Branch'' THEN 1 WHEN ''Panthapath Branch'' THEN 2 WHEN ''Mirpur Branch'' THEN 3 WHEN ''Moghbazar Branch'' THEN 4 WHEN ''Chawkbazar Branch'' THEN 5 ELSE 99 END','{"schema":{"fields":[{"name":"branch","type":"STRING","mode":"NULLABLE"},{"name":"attendance","type":"INTEGER","mode":"NULLABLE"},{"name":"admissions","type":"INTEGER","mode":"NULLABLE"},{"name":"ata_percent","type":"FLOAT","mode":"NULLABLE"}]},"rows":[{"f":[{"v":"Uttara Branch"},{"v":"201"},{"v":"88"},{"v":"44.0"}]},{"f":[{"v":"Panthapath Branch"},{"v":"197"},{"v":"109"},{"v":"55.0"}]},{"f":[{"v":"Mirpur Branch"},{"v":"250"},{"v":"36"},{"v":"14.0"}]},{"f":[{"v":"Moghbazar Branch"},{"v":"144"},{"v":"71"},{"v":"49.0"}]},{"f":[{"v":"Chawkbazar Branch"},{"v":"234"},{"v":"63"},{"v":"27.0"}]}],"jobComplete":true}','2026-03-18 13:13:02.693516+00'),
('bf0024eb-6fc8-4629-8dc2-03e4f53f6d72','81cd94ec-c5a9-40de-88ba-12d4d6aa49ce','SELECT FORMAT_DATE(''%Y-%m'', Date) AS month, SUM(CAST(Amount AS FLOAT64)) AS revenue_collected_amount FROM `tenms-userdb.english_centre.offline_transactions_gsheet_v3` WHERE Date >= DATE ''2026-01-01'' GROUP BY month ORDER BY month','{"schema":{"fields":[{"name":"month","type":"STRING","mode":"NULLABLE"},{"name":"revenue_collected_amount","type":"FLOAT","mode":"NULLABLE"}]},"rows":[{"f":[{"v":"2026-01"},{"v":"1.7456E7"}]},{"f":[{"v":"2026-02"},{"v":"7199800.0"}]},{"f":[{"v":"2026-03"},{"v":"2641970.0"}]}],"jobComplete":true}','2026-03-20 08:33:33.606544+00'),
('a1d4f350-3394-4204-8e0e-ef521a0b447d','cf4bf19c-98be-4d4c-8479-afa0d027c461','WITH regs AS (SELECT COUNT(DISTINCT contact) AS registrations FROM `tenms-userdb.Marketing_Leads.offline_leads_api` WHERE branch = ''Mirpur Branch'' AND submission_date = CURRENT_DATE()), att AS (SELECT COUNT(DISTINCT contact) AS attendance FROM `tenms-userdb.Marketing_Leads.offline_leads_api` WHERE branch = ''Mirpur Branch'' AND attendance_date = CURRENT_DATE()), adm AS (SELECT COUNT(DISTINCT Mobile_Number) AS admissions FROM `tenms-userdb.english_centre.offline_admissions_gsheet_v3` WHERE branch = ''Mirpur Branch'' AND admission_date = CURRENT_DATE()), walk AS (SELECT COUNT(DISTINCT mobile_number) AS walk_ins FROM `tenms-userdb.ab_ihelp_report_db.visitor_ledger_view` WHERE branch = ''Mirpur Branch'' AND visit_type = ''Walk-in'' AND visiting_date = CURRENT_DATE()), walk_adm AS (SELECT COUNT(DISTINCT Mobile_Number) AS walk_in_admissions FROM `tenms-userdb.english_centre.offline_admissions_gsheet_v3` WHERE branch = ''Mirpur Branch'' AND admission_date = CURRENT_DATE() AND Free_Class_Slot = ''Walk-in''), rev AS (SELECT SUM(CAST(Amount AS FLOAT64)) AS revenue_collection FROM `tenms-userdb.english_centre.offline_transactions_gsheet_v3` WHERE branch = ''Mirpur Branch'' AND Date = CURRENT_DATE()) SELECT regs.registrations, att.attendance, adm.admissions, ROUND(SAFE_DIVIDE(att.attendance, regs.registrations) * 100, 2) AS rta_percent, ROUND(SAFE_DIVIDE(adm.admissions, att.attendance) * 100, 2) AS ata_percent, walk.walk_ins, walk_adm.walk_in_admissions, IFNULL(rev.revenue_collection, 0) AS revenue_collection FROM regs CROSS JOIN att CROSS JOIN adm CROSS JOIN walk CROSS JOIN walk_adm CROSS JOIN rev','{"schema":{"fields":[{"name":"registrations","type":"INTEGER","mode":"NULLABLE"},{"name":"attendance","type":"INTEGER","mode":"NULLABLE"},{"name":"admissions","type":"INTEGER","mode":"NULLABLE"},{"name":"rta_percent","type":"FLOAT","mode":"NULLABLE"},{"name":"ata_percent","type":"FLOAT","mode":"NULLABLE"},{"name":"walk_ins","type":"INTEGER","mode":"NULLABLE"},{"name":"walk_in_admissions","type":"INTEGER","mode":"NULLABLE"},{"name":"revenue_collection","type":"FLOAT","mode":"NULLABLE"}]},"rows":[{"f":[{"v":"13"},{"v":"0"},{"v":"0"},{"v":"0.0"},{"v":null},{"v":"0"},{"v":"0"},{"v":"0.0"}]}],"jobComplete":true}','2026-03-21 19:33:47.105895+00'),
('4a3e8be9-8d69-4272-a9cf-9a70ba4e592b','761f43c3-4f33-4ae5-a83e-16c6cf5b3521','SELECT branch, COUNT(DISTINCT contact) AS registrations, COUNT(DISTINCT CASE WHEN attendance_status IN (''present'',''present_early'',''present_late'') THEN contact END) AS attendance, ROUND(SAFE_DIVIDE(COUNT(DISTINCT CASE WHEN attendance_status IN (''present'',''present_early'',''present_late'') THEN contact END), COUNT(DISTINCT contact)) * 100, 2) AS rta_percentage FROM `tenms-userdb.Marketing_Leads.offline_leads_api` WHERE submission_date >= DATE ''2026-01-01'' GROUP BY branch ORDER BY branch','{"schema":{"fields":[{"name":"branch","type":"STRING","mode":"NULLABLE"},{"name":"registrations","type":"INTEGER","mode":"NULLABLE"},{"name":"attendance","type":"INTEGER","mode":"NULLABLE"},{"name":"rta_percentage","type":"FLOAT","mode":"NULLABLE"}]},"rows":[{"f":[{"v":null},{"v":"4930"},{"v":"0"},{"v":"0.0"}]},{"f":[{"v":"Chawkbazar Branch"},{"v":"9097"},{"v":"852"},{"v":"9.37"}]},{"f":[{"v":"Mirpur Branch"},{"v":"10086"},{"v":"1244"},{"v":"12.33"}]},{"f":[{"v":"Moghbazar Branch"},{"v":"5656"},{"v":"729"},{"v":"12.89"}]},{"f":[{"v":"Panthapath Branch"},{"v":"6093"},{"v":"896"},{"v":"14.71"}]},{"f":[{"v":"Uttara Branch"},{"v":"12405"},{"v":"856"},{"v":"6.9"}]}],"jobComplete":true}','2026-03-21 19:53:17.616512+00'),
